    // Calculate all possible end times for land and water rides
    const landEndTimes = [];
    for (let i = 0; i < landStartTime.length; i++) {
        // The ride can start at its earliest time or later
        // We consider starting at the earliest time for the minimal end time
        landEndTimes.push(landStartTime[i] + landDuration[i]);
    }

    const waterEndTimes = [];
    for (let j = 0; j < waterStartTime.length; j++) {
        // The ride can start at its earliest time or later
        // We consider starting at the earliest time for the minimal end time
        waterEndTimes.push(waterStartTime[j] + waterDuration[j]);
    }

    // Try all combinations of land and water rides
    let minEndTime = Infinity;
    for (let i = 0; i < landEndTimes.length; i++) {
        for (let j = 0; j < waterEndTimes.length; j++) {
            // Calculate the end time if we take land ride i first, then water ride j
            const landEnd = landEndTimes[i];
            const waterStart = Math.max(landEnd, waterStartTime[j]);
            const waterEnd = waterStart + waterDuration[j];
            minEndTime = Math.min(minEndTime, waterEnd);

            // Calculate the end time if we take water ride j first, then land ride i
            const waterEnd2 = waterEndTimes[j];
            const landStart = Math.max(waterEnd2, landStartTime[i]);
            const landEnd2 = landStart + landDuration[i];
            minEndTime = Math.min(minEndTime, landEnd2);
        }
    }

    return minEndTime;
}

